package com.example.demo.controller;
import com.example.demo.dto.*; import com.example.demo.service.SalesService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/auth") public class AuthController { private final SalesService service; public AuthController(SalesService service){this.service=service;} @PostMapping("/register") @ResponseStatus(HttpStatus.CREATED) public AuthResponse register(@RequestBody AuthRequest request){return service.register(request);} @PostMapping("/login") public AuthResponse login(@RequestBody AuthRequest request){return service.login(request);}@PostMapping("/forgot-password") @ResponseStatus(HttpStatus.NO_CONTENT) public void forgotPassword(@RequestBody ForgotPasswordRequest request){service.resetPassword(request);} }
